import { Component, OnInit } from '@angular/core';
import { Injectable } from '@angular/core';
import { ActivatedRoute } from '@angular/router';

@Injectable({ providedIn: 'root' })
export class BeaconService {
  private beacons = [
    { id: 1, name: 'alpha' },
    { id: 2, name: 'beta' },
    { id: 3, name: 'gamma' },
  ];

  find(id) {
    return this.beacons.find(b => b.id === id) ?? null;
  }
}

export class BeaconDetailComponent implements OnInit {
  beacon = null;
  route;
  beaconService;

  constructor(route, beaconService) {
    this.route = route;
    this.beaconService = beaconService;
  }

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id');
    this.beacon = this.beaconService.find(Number(id));
  }

  get displayName() {
    return this.beacon ? this.beacon.name.toUpperCase() : 'NOT FOUND';
  }
}
